# Salva o arquivo
output_dir = Path("static/quizzes/cfe/fraud_investigation")
output_dir.mkdir(parents=True, exist_ok=True)

# Determina o proximo numero de quiz disponivel
existing = list(output_dir.glob("quiz_*_pt.json"))
nums = []
for f in existing:
    try:
        nums.append(int(f.stem.split("_")[1]))
    except:
        pass
next_num = max(nums) + 1 if nums else 1

output = {
    "cert_id": "cfe",
    "domain_id": "fraud_investigation",
    "quiz_num": next_num,
    "domain_name": "Fraud Investigation",
    "cert_name": "CFE / ACFE",
    "lang": "pt",
    "questions": questions
}

path = output_dir / f"quiz_{next_num:03d}_pt.json"
path.write_text(json.dumps(output, ensure_ascii=False, indent=2), encoding="utf-8")

print(f"OK - {len(questions)} questoes salvas em {path}")
print(f"Quiz numero: {next_num}")
